import { useEffect, useState, useRef } from 'react'
import { createPortal } from 'react-dom'
import './CardModal.css'
import BlockEditor from '../CardModal/BlockEditor.jsx'

export default function CardModal({ card, onClose, onUpdate, onDelete }) {
  // Edit state
  const [isEditingTitle, setIsEditingTitle] = useState(false)
  const [editTitle, setEditTitle]           = useState(card.title)
  const [isEditingAssignee, setIsEditingAssignee] = useState(false)
  const [editAssignee, setEditAssignee]     = useState(card.assignee ?? '')
  const [isEditingDescription, setIsEditingDescription] = useState(false)
  const [isSaving, setIsSaving]             = useState(false)
  const [saveError, setSaveError]           = useState(null)

  // Delete state
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)
  const [isDeleting, setIsDeleting]               = useState(false)

  // Focus refs
  const titleInputRef    = useRef(null)
  const assigneeInputRef = useRef(null)

  // Focus effects
  useEffect(() => {
    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
  }, [isEditingTitle])

  useEffect(() => {
    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
  }, [isEditingAssignee])

  // Escape key handler — replaces the original handler
  useEffect(() => {
    function onKey(e) {
      if (e.key !== 'Escape') return
      if (isEditingTitle) {
        setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
      } else if (isEditingAssignee) {
        setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
      } else if (isEditingDescription) {
        // BlockEditor owns its own Escape handler; CardModal just prevents modal close
      } else {
        onClose()
      }
    }
    document.addEventListener('keydown', onKey)
    return () => document.removeEventListener('keydown', onKey)
  }, [onClose, isEditingTitle, isEditingAssignee, isEditingDescription, card.title, card.assignee])

  // Save handlers
  async function handleSaveTitle() {
    if (editTitle.trim() === '') {
      setSaveError('Title is required')
      return
    }
    setIsSaving(true); setSaveError(null)
    try {
      await onUpdate(card.id, { title: editTitle })
      setIsEditingTitle(false)
    } catch (err) {
      setSaveError(err.message)
    } finally {
      setIsSaving(false)
    }
  }

  async function handleSaveAssignee() {
    setIsSaving(true); setSaveError(null)
    try {
      await onUpdate(card.id, { assignee: editAssignee === '' ? null : editAssignee })
      setIsEditingAssignee(false)
    } catch (err) {
      setSaveError(err.message)
    } finally {
      setIsSaving(false)
    }
  }

  async function handleConfirmDelete() {
    setIsDeleting(true); setSaveError(null)
    try {
      await onDelete(card.id)
      onClose()
    } catch (err) {
      setSaveError(err.message)
      setShowDeleteConfirm(false)
    } finally {
      setIsDeleting(false)
    }
  }

  return createPortal(
    <div className="modal-overlay" onClick={onClose}>
      <div
        className="modal-content"
        role="dialog"
        aria-modal="true"
        aria-label={card.title}
        onClick={e => e.stopPropagation()}
      >
        {/* 1. Close button */}
        <button className="modal-close" onClick={onClose} aria-label="Close">
          ✕
        </button>

        {/* 2. Title field (editable) */}
        {isEditingTitle ? (
          <div className="modal-field-edit">
            <input
              ref={titleInputRef}
              aria-label="Title"
              value={editTitle}
              onChange={e => setEditTitle(e.target.value)}
              onKeyDown={e => { if (e.key === 'Enter') handleSaveTitle() }}
            />
            <button aria-label="Save" onClick={handleSaveTitle} disabled={isSaving}>
              {isSaving ? 'Saving…' : 'Save'}
            </button>
            <button
              aria-label="Cancel"
              disabled={isSaving}
              onClick={() => { setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }}
            >
              Cancel
            </button>
          </div>
        ) : (
          <div className="modal-field-view">
            <h2 className="modal-title">{card.title}</h2>
            <button
              aria-label="Edit title"
              onClick={() => {
                setIsEditingTitle(true); setEditTitle(card.title)
                // Mutual exclusivity: close assignee edit if open
                setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
              }}
            >
              Edit
            </button>
          </div>
        )}

        {/* 3. Assignee field (editable) */}
        {isEditingAssignee ? (
          <div className="modal-field-edit">
            <input
              ref={assigneeInputRef}
              aria-label="Assignee"
              value={editAssignee}
              onChange={e => setEditAssignee(e.target.value)}
              onKeyDown={e => { if (e.key === 'Enter') handleSaveAssignee() }}
            />
            <button aria-label="Save" onClick={handleSaveAssignee} disabled={isSaving}>
              {isSaving ? 'Saving…' : 'Save'}
            </button>
            <button
              aria-label="Cancel"
              disabled={isSaving}
              onClick={() => { setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }}
            >
              Cancel
            </button>
          </div>
        ) : (
          <div className="modal-field-view">
            <p className="modal-assignee">
              <strong>Assignee:</strong> {card.assignee ?? 'Unassigned'}
            </p>
            <button
              aria-label="Edit assignee"
              onClick={() => {
                setIsEditingAssignee(true); setEditAssignee(card.assignee ?? '')
                // Mutual exclusivity: close title edit if open
                setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
              }}
            >
              Edit
            </button>
          </div>
        )}

        {/* 4. Description (BlockNote editor) */}
        <BlockEditor
          content={card.description}
          onSave={(json) => onUpdate(card.id, { description: json })}
          onEditingChange={setIsEditingDescription}
        />

        {/* 5. Error alert */}
        {saveError && <p role="alert" className="modal-error">{saveError}</p>}

        {/* 6. Comments section */}
        <section className="modal-comments">
          <h3 className="modal-comments-heading">Comments</h3>
          {card.comments.length === 0 ? (
            <p className="modal-no-comments">No comments yet</p>
          ) : (
            <ul className="modal-comments-list">
              {card.comments.map(cm => (
                <li key={cm.id} data-testid="comment" className="modal-comment">
                  <div className="modal-comment-meta">
                    <span className="modal-comment-author">{cm.author}</span>
                    <time
                      className="modal-comment-time"
                      dateTime={new Date(cm.created_at).toISOString()}
                    >
                      {new Date(cm.created_at).toLocaleString()}
                    </time>
                  </div>
                  <p className="modal-comment-content">{cm.content}</p>
                </li>
              ))}
            </ul>
          )}
        </section>

        {/* 7. Delete button / confirmation */}
        {showDeleteConfirm ? (
          <div className="modal-delete-confirm" role="region" aria-label="Delete confirmation">
            <p>Are you sure you want to delete this card?</p>
            <button
              aria-label="Confirm delete"
              onClick={handleConfirmDelete}
              disabled={isDeleting}
            >
              {isDeleting ? 'Deleting…' : 'Confirm delete'}
            </button>
            <button
              aria-label="Keep card"
              onClick={() => setShowDeleteConfirm(false)}
              disabled={isDeleting}
            >
              Keep card
            </button>
          </div>
        ) : (
          <button
            className="modal-delete"
            aria-label="Delete"
            onClick={() => setShowDeleteConfirm(true)}
          >
            Delete
          </button>
        )}
      </div>
    </div>,
    document.body
  )
}

import { render, screen, fireEvent, waitFor } from '@testing-library/react'
import { describe, it, expect, vi, beforeEach } from 'vitest'
import { useCreateBlockNote, BlockNoteViewRaw } from '@blocknote/react'
import BlockEditor from './BlockEditor.jsx'

// vi.mock is hoisted — factory must NOT reference module-scope variables
vi.mock('@blocknote/react', () => ({
  useCreateBlockNote: vi.fn(),
  BlockNoteViewRaw: vi.fn(({ editable }) => (
    <div data-testid="blocknote-view" data-editable={String(editable)} />
  )),
}))

// Define mockEditor AFTER vi.mock (it is wired up in beforeEach, not in the factory)
const mockEditor = {
  document: [
    { type: 'paragraph', id: '1', content: [{ type: 'text', text: 'Hello', styles: {} }], props: {} }
  ],
  replaceBlocks: vi.fn(),
}

beforeEach(() => {
  useCreateBlockNote.mockClear()
  useCreateBlockNote.mockReturnValue(mockEditor)
  mockEditor.replaceBlocks.mockClear()
  BlockNoteViewRaw.mockClear()
})

// ---------------------------------------------------------------------------
// Subtask 1 — Basic rendering
// ---------------------------------------------------------------------------
describe('BlockEditor — basic rendering', () => {
  it('renders "No description" when content is null', () => {
    render(<BlockEditor content={null} onSave={vi.fn()} />)
    expect(screen.getByText('No description')).toBeInTheDocument()
  })

  it('renders "No description" when content is undefined', () => {
    render(<BlockEditor content={undefined} onSave={vi.fn()} />)
    expect(screen.getByText('No description')).toBeInTheDocument()
  })

  it('renders "No description" when content is empty string', () => {
    render(<BlockEditor content="" onSave={vi.fn()} />)
    expect(screen.getByText('No description')).toBeInTheDocument()
  })

  it('renders BlockNoteViewRaw in view mode when content is provided', () => {
    render(<BlockEditor content="some content" onSave={vi.fn()} />)
    expect(screen.getByTestId('blocknote-view')).toBeInTheDocument()
  })

  it('renders an "Edit description" button in view mode', () => {
    render(<BlockEditor content={null} onSave={vi.fn()} />)
    expect(screen.getByRole('button', { name: /edit description/i })).toBeInTheDocument()
  })

  it('does not render BlockNoteViewRaw when content is null', () => {
    render(<BlockEditor content={null} onSave={vi.fn()} />)
    expect(screen.queryByTestId('blocknote-view')).not.toBeInTheDocument()
  })
})

// ---------------------------------------------------------------------------
// Subtask 2 — Initialization / parseContent
// ---------------------------------------------------------------------------
describe('BlockEditor — initialization', () => {
  it('calls useCreateBlockNote with parsed JSON content when content is valid JSON', () => {
    const jsonContent = '[{"type":"paragraph","content":[{"type":"text","text":"hello","styles":{}}]}]'
    render(<BlockEditor content={jsonContent} onSave={vi.fn()} />)
    expect(useCreateBlockNote).toHaveBeenCalledWith(
      expect.objectContaining({ initialContent: JSON.parse(jsonContent) })
    )
  })

  it('calls useCreateBlockNote with paragraph block fallback when content is plain text', () => {
    render(<BlockEditor content="plain text" onSave={vi.fn()} />)
    expect(useCreateBlockNote).toHaveBeenCalledWith(
      expect.objectContaining({
        initialContent: [{ type: 'paragraph', content: [{ type: 'text', text: 'plain text', styles: {} }] }]
      })
    )
  })

  it('calls useCreateBlockNote with undefined initialContent when content is null', () => {
    render(<BlockEditor content={null} onSave={vi.fn()} />)
    expect(useCreateBlockNote).toHaveBeenCalledWith(
      expect.objectContaining({ initialContent: undefined })
    )
  })
})

// ---------------------------------------------------------------------------
// Subtask 3 — Edit / read-only mode toggle
// ---------------------------------------------------------------------------
describe('BlockEditor — mode toggle', () => {
  it('clicking "Edit description" enters edit mode (shows Save and Cancel buttons)', () => {
    render(<BlockEditor content="some content" onSave={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    expect(screen.getByRole('button', { name: /save description/i })).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /cancel description edit/i })).toBeInTheDocument()
  })

  it('in edit mode, BlockNoteViewRaw receives editable={true}', () => {
    render(<BlockEditor content="some content" onSave={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    expect(screen.getByTestId('blocknote-view')).toHaveAttribute('data-editable', 'true')
  })

  it('in view mode, BlockNoteViewRaw receives editable={false} when content is provided', () => {
    render(<BlockEditor content="some content" onSave={vi.fn()} />)
    expect(screen.getByTestId('blocknote-view')).toHaveAttribute('data-editable', 'false')
  })

  it('clicking Cancel exits edit mode', () => {
    render(<BlockEditor content="some content" onSave={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /cancel description edit/i }))
    expect(screen.getByRole('button', { name: /edit description/i })).toBeInTheDocument()
  })

  it('clicking Cancel hides Save and Cancel buttons', () => {
    render(<BlockEditor content="some content" onSave={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /cancel description edit/i }))
    expect(screen.queryByRole('button', { name: /save description/i })).not.toBeInTheDocument()
    expect(screen.queryByRole('button', { name: /cancel description edit/i })).not.toBeInTheDocument()
  })

  it('Escape key cancels edit mode when editing', () => {
    render(<BlockEditor content="some content" onSave={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.keyDown(document, { key: 'Escape' })
    expect(screen.queryByRole('button', { name: /save description/i })).not.toBeInTheDocument()
    expect(screen.getByRole('button', { name: /edit description/i })).toBeInTheDocument()
  })

  it('Escape key does not affect component when not in edit mode', () => {
    render(<BlockEditor content="some content" onSave={vi.fn()} />)
    fireEvent.keyDown(document, { key: 'Escape' })
    expect(screen.getByRole('button', { name: /edit description/i })).toBeInTheDocument()
    expect(screen.queryByRole('button', { name: /save description/i })).not.toBeInTheDocument()
  })

  it('calls onEditingChange with true when Edit is clicked', () => {
    const onEditingChange = vi.fn()
    render(<BlockEditor content="some content" onSave={vi.fn()} onEditingChange={onEditingChange} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    expect(onEditingChange).toHaveBeenCalledWith(true)
  })

  it('calls onEditingChange with false when Cancel is clicked', () => {
    const onEditingChange = vi.fn()
    render(<BlockEditor content="some content" onSave={vi.fn()} onEditingChange={onEditingChange} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /cancel description edit/i }))
    expect(onEditingChange).toHaveBeenCalledWith(false)
  })

  it('calls onEditingChange with false when Save succeeds', async () => {
    const onEditingChange = vi.fn()
    const onSave = vi.fn().mockResolvedValue(undefined)
    render(<BlockEditor content="some content" onSave={onSave} onEditingChange={onEditingChange} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /save description/i }))
    await waitFor(() => expect(onEditingChange).toHaveBeenCalledWith(false))
  })

  it('Cancel calls editor.replaceBlocks to reset content', () => {
    render(<BlockEditor content="some content" onSave={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /cancel description edit/i }))
    expect(mockEditor.replaceBlocks).toHaveBeenCalled()
  })

  it('Cancel with null content calls replaceBlocks with a minimum paragraph block', () => {
    render(<BlockEditor content={null} onSave={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /cancel description edit/i }))
    expect(mockEditor.replaceBlocks).toHaveBeenCalledWith(
      mockEditor.document,
      [{ type: 'paragraph', content: [] }]
    )
  })
})

// ---------------------------------------------------------------------------
// Subtask 4 — Save / JSON serialization
// ---------------------------------------------------------------------------
describe('BlockEditor — save', () => {
  it('Save calls onSave with JSON.stringify of editor.document', async () => {
    const onSave = vi.fn().mockResolvedValue(undefined)
    render(<BlockEditor content="some content" onSave={onSave} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /save description/i }))
    await waitFor(() => expect(onSave).toHaveBeenCalledWith(JSON.stringify(mockEditor.document)))
  })

  it('Save button is disabled and shows "Saving…" while pending', () => {
    const onSave = vi.fn().mockReturnValue(new Promise(() => {}))
    render(<BlockEditor content="some content" onSave={onSave} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /save description/i }))
    const saveBtn = screen.getByRole('button', { name: /save description/i })
    expect(saveBtn).toBeDisabled()
    expect(saveBtn).toHaveTextContent('Saving…')
  })

  it('Cancel button is disabled while saving', () => {
    const onSave = vi.fn().mockReturnValue(new Promise(() => {}))
    render(<BlockEditor content="some content" onSave={onSave} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /save description/i }))
    expect(screen.getByRole('button', { name: /cancel description edit/i })).toBeDisabled()
  })

  it('Save exits edit mode on success', async () => {
    const onSave = vi.fn().mockResolvedValue(undefined)
    render(<BlockEditor content="some content" onSave={onSave} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /save description/i }))
    await waitFor(() => expect(screen.queryByRole('button', { name: /save description/i })).not.toBeInTheDocument())
    expect(screen.getByRole('button', { name: /edit description/i })).toBeInTheDocument()
  })

  it('Save stays in edit mode on rejection', async () => {
    const onSave = vi.fn().mockRejectedValue(new Error('Server error'))
    render(<BlockEditor content="some content" onSave={onSave} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /save description/i }))
    await waitFor(() => expect(onSave).toHaveBeenCalled())
    expect(screen.getByRole('button', { name: /save description/i })).toBeInTheDocument()
  })

  it('Save shows error alert with message on rejection', async () => {
    const onSave = vi.fn().mockRejectedValue(new Error('Save failed'))
    render(<BlockEditor content="some content" onSave={onSave} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /save description/i }))
    await waitFor(() => expect(screen.getByRole('alert')).toHaveTextContent('Save failed'))
  })

  it('no error alert shown on initial render', () => {
    render(<BlockEditor content="some content" onSave={vi.fn()} />)
    expect(screen.queryByRole('alert')).not.toBeInTheDocument()
  })

  it('error alert clears after a second Save succeeds', async () => {
    const onSave = vi.fn()
      .mockRejectedValueOnce(new Error('fail'))
      .mockResolvedValueOnce(undefined)
    render(<BlockEditor content="some content" onSave={onSave} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    // First save — fails
    fireEvent.click(screen.getByRole('button', { name: /save description/i }))
    await waitFor(() => expect(screen.getByRole('alert')).toBeInTheDocument())
    // Second save — succeeds
    fireEvent.click(screen.getByRole('button', { name: /save description/i }))
    await waitFor(() => expect(screen.queryByRole('alert')).not.toBeInTheDocument())
  })
})

  it('renders "No comments yet" when comments array is empty', () => {
    render(<CardModal card={card} onClose={vi.fn()} onUpdate={vi.fn()} onDelete={vi.fn()} />)
    expect(screen.getByText(/no comments yet/i)).toBeInTheDocument()
  })

  it('does not render "No comments yet" when comments exist', () => {
    render(<CardModal card={cardWithComments} onClose={vi.fn()} onUpdate={vi.fn()} onDelete={vi.fn()} />)
    expect(screen.queryByText(/no comments yet/i)).not.toBeInTheDocument()
  })
})

// ---------------------------------------------------------------------------
// CardModal — description (BlockEditor integration)
// ---------------------------------------------------------------------------
describe('CardModal — description', () => {
  it('renders BlockEditor in place of the static description paragraph', () => {
    render(<CardModal card={card} onClose={vi.fn()} onUpdate={vi.fn()} onDelete={vi.fn()} />)
    expect(screen.getByTestId('block-editor')).toBeInTheDocument()
  })

  it('BlockEditor receives card.description as its content prop', () => {
    render(<CardModal card={{ ...card, description: 'Some description' }} onClose={vi.fn()} onUpdate={vi.fn()} onDelete={vi.fn()} />)
    expect(screen.getByTestId('block-editor')).toHaveTextContent('Some description')
  })

  it('BlockEditor onSave prop calls onUpdate(card.id, { description: json })', async () => {
    const onUpdate = vi.fn().mockResolvedValue({ ...card, description: '{"blocks":"test"}' })
    render(<CardModal card={card} onClose={vi.fn()} onUpdate={onUpdate} onDelete={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /save description/i }))
    await waitFor(() => expect(onUpdate).toHaveBeenCalledWith('1', { description: '{"blocks":"test"}' }))
  })

  it('Escape does not close modal when BlockEditor reports isEditing=true', () => {
    const onClose = vi.fn()
    render(<CardModal card={card} onClose={onClose} onUpdate={vi.fn()} onDelete={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.keyDown(document.body, { key: 'Escape' })
    expect(onClose).not.toHaveBeenCalled()
  })

  it('Escape closes modal after description editing ends', () => {
    const onClose = vi.fn()
    render(<CardModal card={card} onClose={onClose} onUpdate={vi.fn()} onDelete={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /edit description/i }))
    fireEvent.click(screen.getByRole('button', { name: /cancel description edit/i }))
    fireEvent.keyDown(document.body, { key: 'Escape' })
    expect(onClose).toHaveBeenCalledTimes(1)
  })
})

